function check_isAuthorized_expiry(address account, uint256 expiry, uint256 blockTime) public {
    vm.assume(expiry != UNAUTHORIZED);
    vm.assume(expiry != AUTHORIZED);
    vm.assume(blockTime >= expiry);
    vm.warp(blockTime);

    // Setup permission with expiry
    Permission storage perm = _setupPermission(expiry);
    perm.allowed[account] = false;

    bool result = _isAuthorized(perm, account);

    // After expiry, if account is not in allowed list, should return false
    assert(!result);
}
